const trigger = $('Execute Workflow Trigger').first().json;
const chunkFiles = trigger.chunk_files || [];
const allFiles = $json.files || [];
const existingFiles = chunkFiles.length > 0
  ? allFiles.filter(f => chunkFiles.includes(f.path))
  : allFiles;
const task = { ...(trigger.task || {}) };
if (chunkFiles.length > 0) task.files = chunkFiles;
return [{ json: {
  task,
  existing_files: existingFiles,
  plan_document: trigger.plan_document || '',
  project_goal: trigger.project_goal || '',
  previous_feedback: '',
  project_id: trigger.project_id
} }];

const trigger = $('Execute Workflow Trigger').first().json;
const chunkFiles = trigger.chunk_files || [];
const existingFiles = $('Build Code Input').first().json.existing_files || [];
const newFiles = $json.files || [];
const fileMap = new Map();
existingFiles.forEach(f => fileMap.set(f.path, f));
newFiles.forEach(f => fileMap.set(f.path, f));
const mergedFiles = chunkFiles.length > 0
  ? Array.from(fileMap.values()).filter(f => chunkFiles.includes(f.path))
  : Array.from(fileMap.values());
return [{ json: {
  files: mergedFiles,
  task: $json.task,
  project_goal: $json.project_goal
} }];

const review = $json.review || {};
const parseFailed = !!review.raw_output;
const score = review.quality_score || 0;
const jobComplete = review.job_complete === true;
const criticalCount = (review.security_issues || []).filter(i => i.severity === 'critical').length;
let shouldPass;
if (parseFailed) {
  shouldPass = true;
} else {
  shouldPass = (jobComplete || score >= 80) && criticalCount === 0;
}
const feedback = [
  ...(review.security_issues || []).map(i => `SECURITY ${i.severity.toUpperCase()}: ${i.issue} \u2192 ${i.fix}`),
  ...(review.quality_improvements || []).map(a => `QUALITY: ${a.area} \u2192 ${a.fix}`),
  ...(parseFailed ? ['REVIEW: Parser failed \u2014 accepting code as-is'] : [])
].join('\n');
return [{ json: {
  should_pass: shouldPass,
  files: $json.files || [],
  review,
  feedback
} }];

